styles:
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    :root {
      --sidebar-bg: #DAE4F8;
      --main-bg: #FFFCF8;
      --blue: #448AFF;
      --blue-dark: #3a7aee;
      --text: #1a1a1a;
      --muted: #6b6b6b;
      --brown-border: #d4b896;
      --card-hover: #FFEED5;
      --star-filled: #f5c842;
      --star-outline: #f5c842;
      --sidebar-width: 248px;
      --font: 'Montserrat', sans-serif;
    }

    html, body { height: 100%; }

    body {
      font-family: var(--font);
      background: var(--main-bg);
      color: var(--text);
      -webkit-font-smoothing: antialiased;
    }

    .app { display: flex; min-height: 100vh; }

    .sidebar {
      width: var(--sidebar-width);
      flex-shrink: 0;
      background: var(--sidebar-bg);
      display: flex;
      flex-direction: column;
      padding: 28px 20px 32px;
      min-height: 100vh;
      position: relative;
      transition: width 0.22s ease, padding 0.22s ease;
    }

    .sidebar__collapse {
      position: absolute;
      top: 14px;
      right: 12px;
      width: 34px;
      height: 34px;
      border: none;
      border-radius: 8px;
      background: transparent;
      color: var(--blue);
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .sidebar__collapse:hover { background: rgba(68, 138, 255, 0.12); }
    .sidebar__collapse svg { width: 22px; height: 22px; display: block; }
    .app.is-sidebar-collapsed .sidebar__collapse { display: none; }

    .sidebar__toggle {
      width: 54px;
      height: 54px;
      margin: 0 auto 18px;
      border: none;
      border-radius: 16px;
      background: rgba(68, 138, 255, 0.12);
      display: none;
      align-items: center;
      justify-content: center;
      cursor: pointer;
    }

    .app.is-sidebar-collapsed .sidebar__toggle { display: flex; }

    .sidebar__toggle img {
      width: 32px;
      height: 32px;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
    }

    .sidebar__brand {
      display: flex;
      flex-direction: column;
      align-items: center;
      text-align: center;
      margin-bottom: 36px;
    }

    .sidebar__logo {
      width: 120px;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
      margin-bottom: 4px;
    }

    .sidebar__title {
      font-size: 15px;
      font-weight: 800;
      color: var(--blue);
      letter-spacing: 0.06em;
    }

    .nav { list-style: none; display: flex; flex-direction: column; gap: 6px; }

    .nav a {
      display: flex;
      align-items: center;
      gap: 12px;
      padding: 12px 16px;
      border-radius: 12px;
      color: var(--blue);
      font-size: 14px;
      font-weight: 600;
      text-decoration: none;
      transition: background 0.15s ease;
    }

    .nav a svg { width: 20px; height: 20px; flex-shrink: 0; stroke: currentColor; fill: none; }
    .nav a:hover:not(.is-active) { background: rgba(68, 138, 255, 0.12); }
    .nav a.is-active { background: var(--blue); color: #fff; }
    .nav a.is-active svg { stroke: #fff; }
    .nav a .nav-icon--saved { stroke: none; }
    .nav a .nav-icon--saved path { fill: currentColor; }
    .nav a .nav-icon--attendance { stroke: none; }
    .nav a .nav-icon--attendance path { fill: currentColor; }
    .nav a .nav-icon--events { stroke: none; }
    .nav a .nav-icon--events path { fill: currentColor; }
    .nav a .nav-icon--home { stroke: none; }
    .nav a .nav-icon--home path { fill: currentColor; }
    .nav a .nav-icon--certificates { stroke: none; }
    .nav a .nav-icon--certificates path { fill: currentColor; }
    .nav a.is-active [class*="nav-icon--"] > g { filter: none; }

    .sidebar__spacer { flex: 1; min-height: 24px; }
    .nav--bottom { margin-top: auto; padding-top: 16px; }

    .app.is-sidebar-collapsed .sidebar { width: 102px; padding: 28px 12px 24px; }
    .app.is-sidebar-collapsed .sidebar__brand { display: none; }
    .app.is-sidebar-collapsed .nav a { justify-content: center; gap: 0; padding: 14px 0; font-size: 0; }
    .app.is-sidebar-collapsed .nav a svg { width: 24px; height: 24px; }
    .app.is-sidebar-collapsed .nav a.is-active { width: 56px; margin: 0 auto; }

    .main {
      flex: 1;
      min-width: 0;
      overflow-y: auto;
      padding: 32px 40px 48px;
    }

    .main__top {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 16px;
      margin-bottom: 28px;
    }

    .main__greeting {
      font-size: clamp(1.75rem, 3vw, 2.25rem);
      font-weight: 700;
      color: var(--blue);
      line-height: 1.15;
    }

    .main__tools {
      display: flex;
      align-items: center;
      gap: 14px;
    }

    .main__user-name {
      font-size: 14px;
      font-weight: 600;
      color: var(--blue);
      white-space: nowrap;
    }

    .tool-btn {
      width: 40px;
      height: 40px;
      border: none;
      border-radius: 50%;
      background: transparent;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      color: var(--blue);
      flex-shrink: 0;
    }

    .tool-btn:hover { background: rgba(68, 138, 255, 0.1); }
    .tool-btn--avatar { background: #c5d9fc; }
    .tool-btn--help { background: #c5d9fc; color: #fff; }
    .tool-btn--help:hover { background: #b5cffc; color: #fff; }
    .tool-btn--help svg { width: 22px; height: 22px; flex-shrink: 0; }
    .tool-btn svg { width: 22px; height: 22px; }

    .sign-intro { margin-bottom: 28px; }

    .sign-intro__title {
      font-size: clamp(1.5rem, 2.8vw, 2rem);
      font-weight: 700;
      color: var(--blue);
      margin-bottom: 8px;
      line-height: 1.2;
    }

    .sign-intro__subtitle {
      font-size: 15px;
      font-weight: 500;
      color: var(--text);
      line-height: 1.5;
    }

    .sign-form-card {
      background: #fff;
      border: 1px solid var(--brown-border);
      border-radius: 14px;
      padding: 28px 32px 32px;
      margin-bottom: 28px;
    }

    .form-field { margin-bottom: 24px; }
    .form-field:last-child { margin-bottom: 0; }

    .form-field__label {
      display: block;
      font-size: 14px;
      font-weight: 600;
      color: var(--text);
      margin-bottom: 10px;
    }

    .form-field__input {
      width: 100%;
      height: 44px;
      padding: 0 16px;
      border: 1px solid #d0d0d0;
      border-radius: 10px;
      background: #fff;
      font-family: var(--font);
      font-size: 14px;
      font-weight: 500;
      color: var(--text);
      outline: none;
      transition: border-color 0.15s ease, box-shadow 0.15s ease;
    }

    .form-field__input::placeholder { color: #b0b0b0; }

    .form-field__input:focus {
      border-color: var(--blue);
      box-shadow: 0 0 0 3px rgba(68, 138, 255, 0.12);
    }

    .form-field__select-wrap {
      position: relative;
    }

    .form-field__select {
      width: 100%;
      height: 44px;
      padding: 0 40px 0 16px;
      border: 1px solid #d0d0d0;
      border-radius: 10px;
      background: #fff;
      font-family: var(--font);
      font-size: 14px;
      font-weight: 500;
      color: var(--text);
      outline: none;
      appearance: none;
      cursor: pointer;
      transition: border-color 0.15s ease;
    }

    .form-field__select:invalid,
    .form-field__select option[value=""] {
      color: #b0b0b0;
    }

    .form-field__select:focus {
      border-color: var(--blue);
      box-shadow: 0 0 0 3px rgba(68, 138, 255, 0.12);
    }

    .form-field__select-arrow {
      position: absolute;
      right: 14px;
      top: 50%;
      transform: translateY(-50%);
      pointer-events: none;
      color: var(--muted);
    }

    .form-field__select-arrow svg {
      width: 18px;
      height: 18px;
    }

    .form-stars {
      display: flex;
      align-items: center;
      gap: 6px;
    }

    .form-stars__btn {
      width: 32px;
      height: 32px;
      border: none;
      background: transparent;
      cursor: pointer;
      padding: 0;
      color: var(--star-outline);
      display: flex;
      align-items: center;
      justify-content: center;
      transition: transform 0.1s ease;
    }

    .form-stars__btn:hover { transform: scale(1.1); }

    .form-stars__btn svg {
      width: 28px;
      height: 28px;
      fill: none;
      stroke: currentColor;
      stroke-width: 1.5;
    }

    .form-stars__btn.is-filled svg {
      fill: currentColor;
      stroke: currentColor;
    }

    .form-media__head {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 12px;
      margin-bottom: 14px;
    }

    .form-media__label-group { flex: 1; }

    .form-media__hint {
      font-size: 12px;
      font-weight: 500;
      color: var(--muted);
      margin-top: 4px;
    }

    .form-media__add {
      width: 36px;
      height: 36px;
      border: none;
      border-radius: 8px;
      background: transparent;
      color: var(--blue);
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
      transition: background 0.15s ease;
    }

    .form-media__add:hover { background: rgba(68, 138, 255, 0.1); }
    .form-media__add:disabled { opacity: 0.4; cursor: not-allowed; }
    .form-media__add svg { width: 26px; height: 26px; }

    .form-media__grid {
      display: flex;
      gap: 16px;
      flex-wrap: wrap;
    }

    .form-media__slot {
      width: 100px;
      height: 100px;
      border: 1px dashed #d0d0d0;
      border-radius: 10px;
      background: #fafafa;
      display: flex;
      align-items: center;
      justify-content: center;
      color: #c0c0c0;
      position: relative;
      overflow: hidden;
    }

    .form-media__slot svg {
      width: 32px;
      height: 32px;
    }

    .form-media__slot.has-image {
      border-style: solid;
      border-color: var(--brown-border);
      background: #fff;
    }

    .form-media__slot img {
      width: 100%;
      height: 100%;
      object-fit: cover;
    }

    .form-media__slot-remove {
      position: absolute;
      top: 4px;
      right: 4px;
      width: 22px;
      height: 22px;
      border: none;
      border-radius: 50%;
      background: rgba(0, 0, 0, 0.55);
      color: #fff;
      font-size: 14px;
      line-height: 1;
      cursor: pointer;
      display: none;
      align-items: center;
      justify-content: center;
    }

    .form-media__slot.has-image .form-media__slot-remove { display: flex; }
    .form-media__slot.has-image svg { display: none; }

    .form-field__textarea {
      width: 100%;
      min-height: 140px;
      padding: 14px 16px;
      border: 1px solid #d0d0d0;
      border-radius: 10px;
      background: #fff;
      font-family: var(--font);
      font-size: 14px;
      font-weight: 500;
      color: var(--text);
      line-height: 1.55;
      resize: vertical;
      outline: none;
      transition: border-color 0.15s ease, box-shadow 0.15s ease;
    }

    .form-field__textarea:focus {
      border-color: var(--blue);
      box-shadow: 0 0 0 3px rgba(68, 138, 255, 0.12);
    }

    .sign-submit {
      width: 100%;
      max-width: 100%;
      height: 52px;
      border: none;
      border-radius: 12px;
      background: var(--sidebar-bg);
      color: var(--blue);
      font-family: var(--font);
      font-size: 16px;
      font-weight: 700;
      cursor: pointer;
      transition: background 0.15s ease, transform 0.1s ease;
    }

    .sign-submit:hover { background: #c8d8f5; }
    .sign-submit:active { transform: scale(0.99); }

    .form-media__input { display: none; }

    .main { position: relative; }

    .success-overlay {
      position: absolute;
      inset: 0;
      z-index: 100;
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 32px 24px;
      background: rgba(255, 252, 248, 0.45);
      backdrop-filter: blur(8px);
      -webkit-backdrop-filter: blur(8px);
    }

    .success-overlay[hidden] { display: none; }

    .success-modal {
      width: 100%;
      max-width: 460px;
      padding: 36px 32px 32px;
      background: #fff;
      border: 1.5px solid var(--blue);
      border-radius: 14px;
      text-align: center;
      box-shadow: 0 10px 40px rgba(68, 138, 255, 0.14);
    }

    .success-modal__title {
      font-size: 17px;
      font-weight: 700;
      color: var(--text);
      line-height: 1.45;
      margin-bottom: 12px;
    }

    .success-modal__text {
      font-size: 14px;
      font-weight: 500;
      color: var(--muted);
      line-height: 1.5;
    }

    @media (max-width: 900px) {
      .app { flex-direction: column; }
      .sidebar { width: 100%; min-height: auto; padding: 20px; }
      .sidebar__collapse, .sidebar__toggle { display: none !important; }
      .sidebar__spacer, .nav--bottom { display: none; }
      .main { padding: 24px 20px 40px; }
      .main__user-name { display: none; }
      .sign-form-card { padding: 20px; }
    }

