(function () {
      var app = document.querySelector('.app');
      var toggle = document.getElementById('sidebar-toggle');
      var collapse = document.getElementById('sidebar-collapse');
      var storageKey = 'dc_sidebar_collapsed';

      function setSidebarCollapsed(collapsed) {
        app.classList.toggle('is-sidebar-collapsed', collapsed);
        localStorage.setItem(storageKey, collapsed);
      }

      if (localStorage.getItem(storageKey) === 'true' && window.innerWidth > 900) {
        setSidebarCollapsed(true);
      }

      collapse.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(true);
      });

      toggle.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(false);
      });

      var starBtns = document.querySelectorAll('.form-stars__btn');
      var ratingInput = document.getElementById('feedback-rating');
      var currentRating = 1;

      function setRating(value) {
        currentRating = value;
        ratingInput.value = String(value);
        starBtns.forEach(function (btn) {
          var r = Number(btn.getAttribute('data-rating'));
          btn.classList.toggle('is-filled', r <= value);
        });
      }

      starBtns.forEach(function (btn) {
        btn.addEventListener('click', function () {
          setRating(Number(btn.getAttribute('data-rating')));
        });
      });

      var mediaInput = document.getElementById('media-input');
      var mediaAddBtn = document.getElementById('media-add-btn');
      var slots = document.querySelectorAll('.form-media__slot');
      var uploadedCount = 0;
      var maxFiles = 2;

      function updateAddButton() {
        mediaAddBtn.disabled = uploadedCount >= maxFiles;
      }

      function getNextEmptySlot() {
        for (var i = 0; i < slots.length; i++) {
          if (!slots[i].classList.contains('has-image')) return slots[i];
        }
        return null;
      }

      function addImageToSlot(slot, file) {
        var reader = new FileReader();
        reader.onload = function (e) {
          var existing = slot.querySelector('img');
          if (existing) existing.remove();
          var img = document.createElement('img');
          img.src = e.target.result;
          img.alt = 'Uploaded media';
          slot.appendChild(img);
          slot.classList.add('has-image');
          uploadedCount++;
          updateAddButton();
        };
        reader.readAsDataURL(file);
      }

      mediaAddBtn.addEventListener('click', function () {
        if (uploadedCount < maxFiles) mediaInput.click();
      });

      mediaInput.addEventListener('change', function () {
        var files = Array.from(mediaInput.files || []);
        files.forEach(function (file) {
          if (uploadedCount >= maxFiles) return;
          var slot = getNextEmptySlot();
          if (slot) addImageToSlot(slot, file);
        });
        mediaInput.value = '';
      });

      slots.forEach(function (slot) {
        var removeBtn = slot.querySelector('.form-media__slot-remove');
        removeBtn.addEventListener('click', function (e) {
          e.stopPropagation();
          var img = slot.querySelector('img');
          if (img) img.remove();
          slot.classList.remove('has-image');
          uploadedCount = Math.max(0, uploadedCount - 1);
          updateAddButton();
        });
      });

      updateAddButton();

      document.getElementById('feedback-form').addEventListener('submit', function (e) {
        e.preventDefault();
        var overlay = document.getElementById('success-overlay');
        overlay.hidden = false;
        document.body.style.overflow = 'hidden';
      });

      var successOverlay = document.getElementById('success-overlay');
      var successModal = successOverlay.querySelector('.success-modal');

      successModal.addEventListener('click', function (e) {
        e.stopPropagation();
      });

      successOverlay.addEventListener('click', function () {
        window.location.href = '/feedback';
      });
    })();
